import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {
    "Authorization": f"Bearer {token}",
    "Content-Type": "application/json"
}

billing_account_name = "<billing-account-id>"
billing_profile_name = "<billing-profile-id>"
invoice_section_name = "engineering-dept"

scope = (
    f"/providers/Microsoft.Billing/billingAccounts/{billing_account_name}/"
    f"billingProfiles/{billing_profile_name}/"
    f"invoiceSections/{invoice_section_name}"
)

url = f"https://management.azure.com{scope}/providers/Microsoft.CostManagement/query?api-version=2023-11-01"

query = {
    "type": "ActualCost",
    "timeframe": "TheLastMonth",
    "dataSet": {
        "granularity": "Monthly",
        "aggregation": {
            "totalCost": {"name": "Cost", "function": "Sum"}
        },
        "grouping": [
            {"type": "Dimension", "name": "ServiceName"},
            {"type": "Dimension", "name": "SubscriptionName"}
        ]
    }
}

resp = requests.post(url, headers=headers, json=query)
data = resp.json()

columns = [c["name"] for c in data.get("properties", {}).get("columns", [])]
rows = data.get("properties", {}).get("rows", [])
print(f"{'Service':<35} {'Subscription':<30} {'Cost':>12}")
print("-" * 80)
for row in sorted(rows, key=lambda r: r[columns.index("Cost")], reverse=True)[:10]:
    row_dict = dict(zip(columns, row))
    print(
        f"{str(row_dict.get('ServiceName','')):<35} "
        f"{str(row_dict.get('SubscriptionName','')):<30} "
        f"{row_dict.get('Cost', 0):>12.2f}"
    )

