import requests
import time
from azure.identity import DefaultAzureCredential

def provision_invoice_section(
    billing_account_name: str,
    billing_profile_name: str,
    section_name: str,
    display_name: str,
    cost_center: str,
    department: str,
) -> dict:
    """
    Create an invoice section and return its resource ID.
    Idempotent: returns existing section if it already exists.
    """
    credential = DefaultAzureCredential()
    token = credential.get_token("https://management.azure.com/.default").token
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json"
    }

    base = (
        f"https://management.azure.com/providers/Microsoft.Billing/"
        f"billingAccounts/{billing_account_name}/"
        f"billingProfiles/{billing_profile_name}/"
        f"invoiceSections"
    )

    # Check if it already exists
    existing = requests.get(f"{base}?api-version=2020-05-01", headers=headers)
    for section in existing.json().get("value", []):
        if section["name"] == section_name:
            print(f"Invoice section '{section_name}' already exists.")
            return section

    # Create it
    body = {
        "properties": {
            "displayName": display_name,
            "labels": {
                "cost-center": cost_center,
                "department": department,
            }
        }
    }
    resp = requests.put(
        f"{base}/{section_name}?api-version=2020-05-01",
        headers=headers,
        json=body
    )

    if resp.status_code == 202:
        # Long-running operation
        location = resp.headers.get("Location")
        for _ in range(12):
            poll = requests.get(location, headers=headers)
            if poll.status_code == 200:
                return poll.json()
            time.sleep(5)
        raise TimeoutError("Invoice section creation timed out")

    resp.raise_for_status()
    return resp.json()


# Example: provision three engineering invoice sections
engineering_sections = [
    ("backend-eng",  "Backend Engineering",  "CC-1001", "engineering"),
    ("platform-eng", "Platform Engineering", "CC-1002", "engineering"),
    ("data-eng",     "Data Engineering",     "CC-1003", "engineering"),
]

BILLING_ACCOUNT = "<billing-account-id>"
BILLING_PROFILE = "<billing-profile-id>"

for name, display, cc, dept in engineering_sections:
    result = provision_invoice_section(
        BILLING_ACCOUNT, BILLING_PROFILE, name, display, cc, dept
    )
    print(f"Provisioned: {result.get('name')} — {result.get('properties', {}).get('displayName')}")
